import axios from "axios";

const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || "http://localhost:8080",
  timeout: 20000,
});

// DEV: keep raw error so we can see exact failure in console/network
api.interceptors.response.use(
  (res) => res,
  (err) => {
    console.error("API error raw:", err);
    return Promise.reject(err);
  }
);

export const fetchPatients = () => api.get("/api/patients").then((r) => r.data);
export const fetchDoctors = () => api.get("/api/doctors").then((r) => r.data);
export const createPatient = (data) => api.post("/api/patients", data).then((r) => r.data);
export const createAppointment = (data) => api.post("/api/appointments", data).then((r) => r.data);
export const updateAppointmentStatus = (id, status) => api.patch(`/api/appointments/${id}/status`, { status }).then((r) => r.data);
export const fetchAppointmentsByPatient = (patientId) => api.get(`/api/appointments/patient/${patientId}`).then((r) => r.data);
